def parse_python_file(file_path: str):
    """
    Parse a Python file and print all classes and functions.
    """

    with open(file_path, "r", encoding="utf-8") as f:
        source = f.read()

    tree = ast.parse(source)

    print(f"\n📄 File: {file_path}")
    print("=" * 60)

    for node in ast.walk(tree):

        if isinstance(node, ast.ClassDef):
            print(f"🏛️  Class: {node.name}")

        elif isinstance(node, ast.FunctionDef):
            print(f"⚙️  Function: {node.name}")

        elif isinstance(node, ast.AsyncFunctionDef):
            print(f"⚡ Async Function: {node.name}")

def scan_python_files(repo_path: str):

    python_files = []

    for root, dirs, files in os.walk(repo_path):

        dirs[:] = [
            d for d in dirs
            if d not in IGNORE_FOLDERS
        ]

        for file in files:

            if file.endswith(".py"):

                full_path = os.path.join(root, file)

                python_files.append(full_path)

    return python_files
